mapper.insert:
INSERT INTO event.email_templates
(
     code
    ,name
    ,subject
    ,body_html
    ,variables
    ,is_active
)
VALUES
(
     #{code}
    ,#{name}
    ,#{subject}
    ,#{bodyHtml}
    ,CAST(#{variables} AS jsonb)
    ,TRUE
)
ON CONFLICT (code) DO NOTHING

mapper.select:
SELECT template_seq ,code ,name ,subject ,is_active ,updated_at FROM event.email_templates WHERE code IN
#{code}
ORDER BY array_position(ARRAY[
#{code}
]::varchar[], code)

mapper.update:
UPDATE event.email_templates
SET
     subject = #{saveDto.subject}
    ,body_html = #{saveDto.bodyHtml}
    ,is_active = #{saveDto.isActive}
    ,updated_at = NOW()
WHERE code = #{code}
